// ═══════════════════════════════════════════════════════════════════
// НОРМАЛИЗАТОР БАНКОВСКОЙ ВЫПИСКИ → BusinessEvent
//
// Детерминированный eventId: повторный импорт той же выписки
// не создаст дублей в Firestore (doc.set идемпотентен).
//
// amount всегда в КОПЕЙКАХ (int): 150 000.00 ₽ → 15000000
// Копейки = единственная надёжная форма; float-рубли дают ошибки
// при агрегировании (0.1 + 0.2 ≠ 0.3 в IEEE 754).
//
// businessId вшит в этот воркфлоу = 'opentgp'.
// Для другого клиента — копируем воркфлоу, меняем одну строку.
// ═══════════════════════════════════════════════════════════════════

const crypto = require('crypto');

const BUSINESS_ID = 'opentgp';

// ── UUID v5 (RFC 4122) из строки-подписи транзакции ─────────────────
// Гарантирует: один и тот же номер транзакции + дата + сумма
// → всегда один и тот же UUID. Повторный импорт = idempotent.
function uuidV5(signature) {
  // DNS namespace (RFC 4122, §4.3)
  const NS = Buffer.from('6ba7b8109dad11d180b400c04fd430c8', 'hex');
  const data = Buffer.from(signature, 'utf8');
  const hash = crypto.createHash('sha1').update(Buffer.concat([NS, data])).digest();
  // Set version 5 bits
  hash[6] = (hash[6] & 0x0f) | 0x50;
  // Set variant bits
  hash[8] = (hash[8] & 0x3f) | 0x80;
  const h = hash.toString('hex');
  return `${h.slice(0,8)}-${h.slice(8,12)}-${h.slice(12,16)}-${h.slice(16,20)}-${h.slice(20,32)}`;
}

// ── Парсинг суммы в копейки ──────────────────────────────────────────
// Входные форматы банков:
//   "150 000,00"  (Сбер, русский формат)
//   "150000.00"   (ТБанк CSV)
//   "-5000.50"    (расход — отрицательный)
//   "1,234.56"    (английский формат)
function parseAmountToKopecks(raw) {
  if (raw === undefined || raw === null || raw === '') return null;
  const s = String(raw).trim()
    .replace(/\s/g, '')     // убираем пробелы-разделители тысяч
    .replace(/,(?=\d{2}$)/, '.')  // «150000,00» → «150000.00»
    .replace(/[^0-9.\-]/g, '');   // убираем лишние символы (₽, пробелы)
  const f = parseFloat(s);
  if (isNaN(f)) return null;
  // Math.round убирает погрешность float: 150000.009999... → 15000001
  return Math.round(f * 100);
}

// ── ISO date из российского формата ────────────────────────────────
// «15.06.2026» → «2026-06-15»
// «2026-06-15» → «2026-06-15» (уже ISO)
function toIsoDate(raw) {
  if (!raw) return null;
  const s = String(raw).trim();
  // DD.MM.YYYY
  const ruMatch = s.match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
  if (ruMatch) return `${ruMatch[3]}-${ruMatch[2]}-${ruMatch[1]}`;
  // YYYY-MM-DD already
  if (/^\d{4}-\d{2}-\d{2}/.test(s)) return s.slice(0, 10);
  return null;
}

// ── Маппинг по формату банка ─────────────────────────────────────────
// Добавляй новые банки здесь, не трогая логику ниже.
const BANK_SCHEMA = {
  'ТБанк (Тинькофф) CSV': {
    dateField:          'Дата операции',
    valueDateField:     'Дата платежа',
    amountField:        'Сумма операции',
    counterpartyField:  'Описание',
    purposeField:       'Категория',
    txIdField:          null, // будем хэшировать дату+сумму+описание
  },
  'Сбербанк XLS': {
    dateField:          'Дата операции',
    valueDateField:     'Дата обработки',
    amountField:        'Сумма в валюте карты',
    counterpartyField:  'Место операции',
    purposeField:       'Описание операции',
    txIdField:          null,
  },
  'Альфа-Банк CSV': {
    dateField:          'Дата совершения операции',
    valueDateField:     'Дата обработки',
    amountField:        'Сумма',
    counterpartyField:  'Наименование контрагента',
    purposeField:       'Назначение платежа',
    txIdField:          'Номер документа',
  },
  'Универсальный CSV (;)': {
    dateField:          'date',
    valueDateField:     'value_date',
    amountField:        'amount',
    counterpartyField:  'counterparty',
    purposeField:       'purpose',
    txIdField:          'tx_id',
  },
};

// ── Основная логика ──────────────────────────────────────────────────
const items = $input.all();
const bankFormat = $('Форма загрузки выписки').first().json['Формат банка'];
const schema = BANK_SCHEMA[bankFormat] ?? BANK_SCHEMA['Универсальный CSV (;)'];
const importTs = new Date().toISOString(); // момент импорта, UTC

const results = [];
const errors = [];

for (const item of items) {
  const row = item.json;

  const rawDate = row[schema.dateField];
  const rawValueDate = row[schema.valueDateField] ?? rawDate;
  const rawAmount = row[schema.amountField];
  const counterpartyRaw = String(row[schema.counterpartyField] ?? '').trim();
  const purposeRaw = String(row[schema.purposeField] ?? '').trim();
  const txId = schema.txIdField ? String(row[schema.txIdField] ?? '').trim() : null;

  const valueDate = toIsoDate(rawValueDate);
  const amountKopecks = parseAmountToKopecks(rawAmount);

  // Пропускаем строки без даты или суммы (заголовки, итоги, пустые)
  if (!valueDate || amountKopecks === null || amountKopecks === 0) {
    errors.push({ row, reason: 'missing date or amount' });
    continue;
  }

  // Детерминированный ID: txId (если есть) ИЛИ хэш реквизитов
  const signature = txId
    ? `${BUSINESS_ID}:${txId}`
    : `${BUSINESS_ID}:${valueDate}:${amountKopecks}:${counterpartyRaw.slice(0, 50)}`;
  const eventId = uuidV5(signature);

  // Направление: положительная сумма = поступление, отрицательная = расход
  const isIncoming = amountKopecks > 0;
  const absAmount = Math.abs(amountKopecks);

  const event = isIncoming
    ? {
        type: 'payment_in',
        businessId: BUSINESS_ID,
        eventId,
        ts: importTs,
        valueDate,
        amount: absAmount,
        counterpartyInn: null,
        counterpartyName: counterpartyRaw || 'Не указан',
        purpose: purposeRaw || '',
        matchedInvoiceId: null,
        source: 'statement_import',
      }
    : {
        type: 'payment_out',
        businessId: BUSINESS_ID,
        eventId,
        ts: importTs,
        valueDate,
        amount: absAmount,
        counterpartyInn: null,
        counterpartyName: counterpartyRaw || 'Не указан',
        purpose: purposeRaw || '',
        expenseCategory: purposeRaw || 'прочее',
        source: 'statement_import',
      };

  results.push({ json: event });
}

if (errors.length > 0) {
  console.warn(`[normalize] пропущено ${errors.length} строк без даты/суммы`);
}

console.log(`[normalize] банк: ${bankFormat}, строк: ${items.length}, событий: ${results.length}, пропущено: ${errors.length}`);

return results;

// Собираем итог по всем батчам
const results = $input.all();
let totalEvents = 0;
let totalSkipped = 0;

for (const item of results) {
  totalEvents += item.json.events ?? 0;
  totalSkipped += item.json.skipped ?? 0;
}

const summary = `✅ Импорт выписки завершён\nЗаписано событий: ${totalEvents}\nПропущено: ${totalSkipped}`;
console.log(summary);
return [{ json: { summary, totalEvents, totalSkipped } }];
